import { useEffect, useState } from "react";
import {
  addCommentToTask,
  assignTaskToUser,
  createTask,
  deleteTask,
  getTasksByProject,
  updateTask,
  updateTaskStatus,
  uploadTaskFile,
} from "../services/taskService";

function TaskPage() {
  const initialFormData = {
    title: "",
    description: "",
    priority: "medium",
    deadline: "",
    projectId: "64f111111111111111111111",
    assignedTo: "64f222222222222222222222",
    createdBy: "64f333333333333333333333",
  };

  const [tasks, setTasks] = useState([]);
  const [formData, setFormData] = useState(initialFormData);
  const [editingTaskId, setEditingTaskId] = useState(null);
  const [commentInputs, setCommentInputs] = useState({});
  const [selectedFiles, setSelectedFiles] = useState({});

  const fetchTasks = async () => {
    try {
      const data = await getTasksByProject();
      setTasks(data);
    } catch (error) {
      console.error("Error fetching tasks:", error.message);
    }
  };

  useEffect(() => {
    fetchTasks();
  }, []);

  const handleChange = (e) => {
    setFormData((prev) => ({
      ...prev,
      [e.target.name]: e.target.value,
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      if (editingTaskId) {
        await updateTask(editingTaskId, formData);
        setEditingTaskId(null);
      } else {
        await createTask(formData);
      }

      setFormData(initialFormData);
      fetchTasks();
    } catch (error) {
      console.error("Error saving task:", error.message);
    }
  };

  const handleDelete = async (taskId) => {
    try {
      await deleteTask(taskId);
      fetchTasks();
    } catch (error) {
      console.error("Error deleting task:", error.message);
    }
  };

  const handleStatusChange = async (taskId, newStatus) => {
    try {
      await updateTaskStatus(taskId, newStatus);
      fetchTasks();
    } catch (error) {
      console.error("Error updating status:", error.message);
    }
  };

  const handleAssignChange = async (taskId, newAssignedTo) => {
    try {
      await assignTaskToUser(taskId, newAssignedTo);
      fetchTasks();
    } catch (error) {
      console.error("Error assigning task:", error.message);
    }
  };

  const handleEdit = (task) => {
    setEditingTaskId(task._id);
    setFormData({
      title: task.title || "",
      description: task.description || "",
      priority: task.priority || "medium",
      deadline: task.deadline ? task.deadline.slice(0, 10) : "",
      projectId: task.projectId || "64f111111111111111111111",
      assignedTo: task.assignedTo || "64f222222222222222222222",
      createdBy: task.createdBy || "64f333333333333333333333",
    });
  };

  const handleCancelEdit = () => {
    setEditingTaskId(null);
    setFormData(initialFormData);
  };

  const handleCommentInputChange = (taskId, value) => {
    setCommentInputs((prev) => ({
      ...prev,
      [taskId]: value,
    }));
  };

  const handleAddComment = async (taskId) => {
    try {
      const text = commentInputs[taskId];

      if (!text || !text.trim()) return;

      await addCommentToTask(taskId, {
        text,
        author: "64f333333333333333333333",
      });

      setCommentInputs((prev) => ({
        ...prev,
        [taskId]: "",
      }));

      fetchTasks();
    } catch (error) {
      console.error("Error adding comment:", error.message);
    }
  };

  const handleFileChange = (taskId, file) => {
    setSelectedFiles((prev) => ({
      ...prev,
      [taskId]: file,
    }));
  };

  const handleFileUpload = async (taskId) => {
    try {
      const file = selectedFiles[taskId];

      if (!file) return;

      await uploadTaskFile(taskId, file);

      setSelectedFiles((prev) => ({
        ...prev,
        [taskId]: null,
      }));

      fetchTasks();
    } catch (error) {
      console.error("Error uploading file:", error.message);
    }
  };

  const getDeadlineStatus = (deadline) => {
    if (!deadline) return null;

    const today = new Date();
    const dueDate = new Date(deadline);

    today.setHours(0, 0, 0, 0);
    dueDate.setHours(0, 0, 0, 0);

    const diffTime = dueDate - today;
    const diffDays = diffTime / (1000 * 60 * 60 * 24);

    if (diffDays < 0) {
      return "overdue";
    }

    if (diffDays <= 2) {
      return "near";
    }

    return "normal";
  };

  const renderDeadlineReminder = (task) => {
    if (task.status === "done") return null;

    const status = getDeadlineStatus(task.deadline);

    if (!status || status === "normal") return null;

    if (status === "overdue") {
      return (
        <p
          style={{
            color: "white",
            background: "#d9534f",
            padding: "8px",
            borderRadius: "5px",
            fontWeight: "bold",
            marginTop: "10px",
          }}
        >
          Deadline dépassée
        </p>
      );
    }

    if (status === "near") {
      return (
        <p
          style={{
            color: "#856404",
            background: "#fff3cd",
            padding: "8px",
            borderRadius: "5px",
            fontWeight: "bold",
            marginTop: "10px",
          }}
        >
          Deadline proche
        </p>
      );
    }

    return null;
  };

  return (
    <div style={{ padding: "20px" }}>
      <h1>Task Management</h1>

      <form onSubmit={handleSubmit} style={{ marginBottom: "30px" }}>
        <div style={{ marginBottom: "10px" }}>
          <label>Title</label>
          <br />
          <input
            type="text"
            name="title"
            value={formData.title}
            onChange={handleChange}
            required
          />
        </div>

        <div style={{ marginBottom: "10px" }}>
          <label>Description</label>
          <br />
          <textarea
            name="description"
            value={formData.description}
            onChange={handleChange}
          />
        </div>

        <div style={{ marginBottom: "10px" }}>
          <label>Priority</label>
          <br />
          <select
            name="priority"
            value={formData.priority}
            onChange={handleChange}
          >
            <option value="low">Low</option>
            <option value="medium">Medium</option>
            <option value="high">High</option>
          </select>
        </div>

        <div style={{ marginBottom: "10px" }}>
          <label>Deadline</label>
          <br />
          <input
            type="date"
            name="deadline"
            value={formData.deadline}
            onChange={handleChange}
          />
        </div>

        <button type="submit">
          {editingTaskId ? "Update Task" : "Create Task"}
        </button>

        {editingTaskId && (
          <button
            type="button"
            onClick={handleCancelEdit}
            style={{ marginLeft: "10px" }}
          >
            Cancel
          </button>
        )}
      </form>

      <h2>Task List</h2>

      {tasks.length === 0 ? (
        <p>No tasks found</p>
      ) : (
        tasks.map((task) => (
          <div
            key={task._id}
            style={{
              border: "1px solid #ccc",
              padding: "10px",
              marginBottom: "15px",
              borderRadius: "8px",
            }}
          >
            <h3>{task.title}</h3>
            <p>{task.description}</p>

            <p>
              <strong>Priority:</strong> {task.priority}
            </p>

            <p>
              <strong>Status:</strong> {task.status}
            </p>

            <p>
              <strong>Deadline:</strong>{" "}
              {task.deadline ? task.deadline.slice(0, 10) : "No deadline"}
            </p>

            {renderDeadlineReminder(task)}

            <p>
              <strong>Assigned To:</strong> {task.assignedTo || "Not assigned"}
            </p>

            <div style={{ marginTop: "10px" }}>
              <label>Change Status: </label>
              <select
                value={task.status}
                onChange={(e) => handleStatusChange(task._id, e.target.value)}
              >
                <option value="todo">To do</option>
                <option value="inprogress">In progress</option>
                <option value="done">Done</option>
              </select>
            </div>

            <div style={{ marginTop: "10px" }}>
              <label>Assign To: </label>
              <select
                value={task.assignedTo || ""}
                onChange={(e) => handleAssignChange(task._id, e.target.value)}
              >
                <option value="">Select user</option>
                <option value="64f222222222222222222222">User 1</option>
                <option value="64f999999999999999999999">User 2</option>
                <option value="64f888888888888888888888">User 3</option>
              </select>
            </div>

            <div style={{ marginTop: "10px" }}>
              <button onClick={() => handleEdit(task)}>Edit</button>
              <button
                onClick={() => handleDelete(task._id)}
                style={{ marginLeft: "10px" }}
              >
                Delete
              </button>
            </div>

            <div style={{ marginTop: "15px" }}>
              <h4>Comments</h4>

              {task.comments && task.comments.length > 0 ? (
                task.comments.map((comment) => (
                  <div
                    key={comment._id}
                    style={{
                      background: "#f5f5f5",
                      padding: "8px",
                      marginBottom: "8px",
                      borderRadius: "5px",
                    }}
                  >
                    <p style={{ margin: 0 }}>{comment.text}</p>
                    <small>Author: {comment.author}</small>
                  </div>
                ))
              ) : (
                <p>No comments yet</p>
              )}

              <input
                type="text"
                placeholder="Add a comment"
                value={commentInputs[task._id] || ""}
                onChange={(e) =>
                  handleCommentInputChange(task._id, e.target.value)
                }
                style={{ marginRight: "10px" }}
              />
              <button onClick={() => handleAddComment(task._id)}>
                Add Comment
              </button>
            </div>

            <div style={{ marginTop: "15px" }}>
              <h4>Attachments</h4>

              {task.attachments && task.attachments.length > 0 ? (
                task.attachments.map((file) => (
                  <div key={file._id} style={{ marginBottom: "8px" }}>
                    <a
                      href={`http://localhost:5002/${file.path.replace(/\\/g, "/")}`}
                      target="_blank"
                      rel="noreferrer"
                    >
                      {file.filename}
                    </a>
                  </div>
                ))
              ) : (
                <p>No attachments</p>
              )}

              <input
                type="file"
                onChange={(e) => handleFileChange(task._id, e.target.files[0])}
              />
              <button
                onClick={() => handleFileUpload(task._id)}
                style={{ marginLeft: "10px" }}
              >
                Upload File
              </button>
            </div>
          </div>
        ))
      )}
    </div>
  );
}

export default TaskPage;
